const message = $input.first().json.body.message || $input.first().json.message || '';

const prompt = `You are a helpful TechCorp assistant. Use search_knowledge_base to find relevant documents.

USER QUESTION: ${message}

INSTRUCTIONS:
1. Search for relevant documents (max 4 searches total).
2. Write a natural, conversational blog-style answer. Use paragraphs, not tables or bullet-point lists.
3. Write as if explaining to a colleague over coffee — clear, friendly, informative.
4. Cite document names naturally in your sentences.
5. Put your answer in this JSON format at the very end:
{"answer":"your natural blog-style answer here","sources":["doc1.pdf","doc2.pdf"]}

Do NOT use markdown tables. Do NOT use bullet points. Write in flowing paragraphs.`;

return { chatInput: prompt };

const output = $input.first().json;
let text = output.output || output.text || JSON.stringify(output);

// 1. Try raw JSON parse
try { const p = JSON.parse(text); if (p.answer) return p; } catch(e) {}

// 2. Extract from ```json fence
let m = text.match(/```json\s*([\s\S]*?)```/);
if (!m) m = text.match(/```\s*([\s\S]*?)```/);
if (m) { try { const p = JSON.parse(m[1].trim()); if (p.answer) return p; } catch(e) {} }

// 3. Brace-counting: find first {, track to matching }
const start = text.indexOf('{');
if (start !== -1) {
  let depth = 0, inStr = false, esc = false;
  for (let i = start; i < text.length; i++) {
    const ch = text[i];
    if (esc) { esc = false; continue; }
    if (ch === '\\') { esc = true; continue; }
    if (ch === '"') { inStr = !inStr; continue; }
    if (inStr) continue;
    if (ch === '{') depth++;
    if (ch === '}') { depth--; if (depth === 0) {
      try { const p = JSON.parse(text.substring(start, i + 1)); if (p.answer) return p; } catch(e) {}
      break;
    }}
  }
}

// 4. Fallback: strip code fences and return raw text
const cleaned = text.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
return { answer: cleaned.slice(0, 2000), sources: [] };
